import { ipcRenderer, contextBridge } from "electron";

// --------- Expose some API to the Renderer process ---------
contextBridge.exposeInMainWorld("ipcRenderer", {
  on(...args: Parameters<typeof ipcRenderer.on>) {
    const [channel, listener] = args;
    return ipcRenderer.on(channel, (event, ...args) =>
      listener(event, ...args),
    );
  },
  off(...args: Parameters<typeof ipcRenderer.off>) {
    const [channel, ...omit] = args;
    return ipcRenderer.off(channel, ...omit);
  },
  send(...args: Parameters<typeof ipcRenderer.send>) {
    const [channel, ...omit] = args;
    return ipcRenderer.send(channel, ...omit);
  },
  invoke(...args: Parameters<typeof ipcRenderer.invoke>) {
    const [channel, ...omit] = args;
    return ipcRenderer.invoke(channel, ...omit);
  },

  queryGameServer(host: string, port?: number) {
    return ipcRenderer.invoke('query-game-server', host, port);
  },
  queryGameServers(gameServers: string[], attempts?: number, timeout?: number | number[]) {
    return ipcRenderer.invoke('query-game-servers', gameServers, attempts, timeout);
  },
  checkCsgo2Running() {
    return ipcRenderer.invoke('check-csgo2-running');
  },
  checkGsiConfig(csgo2Path: string) {
    return ipcRenderer.invoke('check-gsi-config', csgo2Path);
  },
  createGsiConfig(csgo2Path: string) {
    return ipcRenderer.invoke('create-gsi-config', csgo2Path);
  },
  startGsiService() {
    return ipcRenderer.invoke('start-gsi-service');
  },
  stopGsiService() {
    return ipcRenderer.invoke('stop-gsi-service');
  },
  checkGsiConnected() {
    return ipcRenderer.invoke('check-gsi-connected');
  },
  launchCs2Cmd(csgo2Path: string, serverMode: 'perfectworld' | 'worldwide' = 'worldwide') {
    return ipcRenderer.invoke('launch-cs2-cmd', csgo2Path, serverMode);
  },
  launchCs2(csgo2Path: string, serverMode: 'perfectworld' | 'worldwide' = 'worldwide', startType: 'steamurl' | 'steamexe' = 'steamurl', steamPath?: string, startItems?: string[]) {
    return ipcRenderer.invoke('launch-cs2', csgo2Path, serverMode, startType, steamPath, startItems);
  },
  waitForCs2Launch(csgo2Path?: string, maxWaitMs: number = 90000) {
    return ipcRenderer.invoke('wait-for-cs2-launch', csgo2Path, maxWaitMs);
  },
  startLogReader(csgo2Path: string) {
    return ipcRenderer.invoke('start-log-reader', csgo2Path);
  },
  stopLogReader() {
    return ipcRenderer.invoke('stop-log-reader');
  },
  autoDetectPaths() {
    return ipcRenderer.invoke('auto-detect-paths');
  },
  getAppVersion() {
    return ipcRenderer.invoke('electron:get-app-version');
  },
});

// --------- Preload scripts loading ---------
function domReady(
  condition: DocumentReadyState[] = ["complete", "interactive"],
) {
  return new Promise((resolve) => {
    if (condition.includes(document.readyState)) {
      resolve(true);
    } else {
      document.addEventListener("readystatechange", () => {
        if (condition.includes(document.readyState)) {
          resolve(true);
        }
      });
    }
  });
}

const safeDOM = {
  append(parent: HTMLElement, child: HTMLElement) {
    if (!Array.from(parent.children).find((e) => e === child)) {
      return parent.appendChild(child);
    }
  },
  remove(parent: HTMLElement, child: HTMLElement) {
    if (Array.from(parent.children).find((e) => e === child)) {
      return parent.removeChild(child);
    }
  },
};

/**
 * https://tobiasahlin.com/spinkit
 * https://connoratherton.com/loaders
 * https://projects.lukehaas.me/css-loaders
 * https://matejkustec.github.io/SpinThatShit
 */
function useLoading() {
  let progressTimer: number | undefined;
  let progressFinishTimer: number | undefined;
  let progressText: HTMLElement | null = null;
  let progressValue = 0;
  const styleContent = `
.app-loading-wrap {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  z-index: 999;
}

.loading-container {
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 100%;
  height: 100%;
  background-image: url('../../src/assets/imgs/loading_bg.png');
  background-size: cover;
  background-repeat: no-repeat;
  background-position: center;
}

.loading-progress {
  position: absolute;
  bottom: 48px;
  left: 50%;
  transform: translateX(-50%);
  width: min(420px, 70vw);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.progress-title {
  font-size: 24px;
  font-weight: 700;
  color: #007aff;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  text-shadow: 0 4px 12px rgba(0, 0, 0, 0.35);
}

.progress-text {
  font-size: 18px;
  font-weight: 700;
  color: #007aff;
  letter-spacing: 0.14em;
  text-shadow: 0 4px 12px rgba(0, 0, 0, 0.35);
}

.loading-image {
  position: absolute;
  width: 200px;
  height: 300px;
  object-fit: contain;
  opacity: 0;
  transition: opacity 0.5s ease-in-out;
  animation: float 2s ease-in-out infinite;
}

.loading-image.active {
  opacity: 1;
}

@keyframes float {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-30px);
  }
}

    `;
  const oStyle = document.createElement("style");
  const oDiv = document.createElement("div");

  oStyle.id = "app-loading-style";
  oStyle.innerHTML = styleContent;
  oDiv.className = "app-loading-wrap";
  oDiv.innerHTML = `
    <div class="loading-container">
      <img class="loading-image" src="data:image/png;base64," alt="Alona1"/>
      <img class="loading-image" src="data:image/png;base64," alt="Alona2">
      <img class="loading-image" src="data:image/png;base64," alt="Alona3">
      <img class="loading-image" src="data:image/png;base64," alt="Alona4">
      <div class="loading-progress">
        <div class="progress-title">CONNECTING</div>
        <div class="progress-text">0%</div>
      </div>
    </div>
  `;

  const setProgress = (value: number) => {
    progressValue = Math.max(0, Math.min(100, value));
    if (progressText) progressText.textContent = `${Math.round(progressValue)}%`;
  };

  return {
    appendLoading() {
      safeDOM.append(document.head, oStyle);
      safeDOM.append(document.body, oDiv);

      // 图片轮播逻辑
      const images = document.querySelectorAll(".loading-image");
      let currentIndex = 0;
      progressText = oDiv.querySelector(".progress-text");
      setProgress(0);
      if (progressTimer) window.clearInterval(progressTimer);
      if (progressFinishTimer) window.clearTimeout(progressFinishTimer);

      // 每5秒切换一张图片
      setInterval(() => {
        // 隐藏当前图片
        images[currentIndex].classList.remove("active");

        // 计算下一张图片的索引
        currentIndex = (currentIndex + 1) % images.length;

        // 显示下一张图片
        images[currentIndex].classList.add("active");
      }, 1000);

      let targetValue = 0;
      progressTimer = window.setInterval(() => {
        if (targetValue >= 90) return;
        targetValue = Math.min(90, targetValue + 2 + Math.random() * 6);
        setProgress(targetValue);
      }, 350);
    },
    removeLoading() {
      if (progressTimer) window.clearInterval(progressTimer);
      if (progressFinishTimer) window.clearTimeout(progressFinishTimer);
      progressText = oDiv.querySelector(".progress-text");
      setProgress(100);
      progressFinishTimer = window.setTimeout(() => {
        safeDOM.remove(document.head, oStyle);
        safeDOM.remove(document.body, oDiv);
      }, 300);
    },
  };
}

const { appendLoading, removeLoading } = useLoading();
domReady().then(appendLoading);

window.onmessage = (ev) => {
  if (ev.data.payload === "removeLoading"){
    removeLoading();
  }
};
